insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Toán', '12', 'Giải tích', 'Khá', 'Cho hàm số y = x^3 - 3x^2 + 2. Giá trị cực đại của hàm số này là bao nhiêu?', '["1","2","3","4"]'::jsonb, '2', 'Tính y'' = 3x^2 - 6x = 3x(x - 2). Cực đại tại x = 0, giá trị y = 2.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Toán', '12', 'Hình học', 'Cơ bản', 'Trong tam giác vuông, cạnh huyền dài 10 và một cạnh góc vuông dài 6. Độ dài cạnh còn lại là bao nhiêu?', '["6","8","4","3"]'::jsonb, '8', 'Theo định lý Pythagore: x^2 + 6^2 = 10^2 -> x^2 = 64 -> x = 8.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Vật lý', '12', 'Dao động cơ', 'Khá', 'Một con lắc lò xo dao động điều hòa với phương trình x = 5 cos(4t) (cm). Chu kỳ dao động là bao nhiêu?', '["π/2 s","π s","π/4 s","2π s"]'::jsonb, 'π/2 s', 'Tần số góc w = 4 rad/s. Chu kỳ T = 2π/w = 2π/4 = π/2.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Vật lý', '12', 'Điện từ', 'Nâng cao', 'Trong mạch RLC nối tiếp, hệ số chất lượng Q = 10, điện trở R = 10Ω. Điện cảm L bằng bao nhiêu?', '["0.1 H","1 H","10 H","100 H"]'::jsonb, '0.1 H', 'Q = ωL/R = 10, R = 10Ω, suy ra ωL = 100, L = 100/ω.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Hóa học', '12', 'Hóa hữu cơ', 'Cơ bản', 'Este là hợp chất hữu cơ nào?', '["R-COOH","R-COOR''","R-OH","R-NH2"]'::jsonb, 'R-COOR''', 'Este có công thức chung R-COOR'' với R, R'' là nhóm alkyl.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Hóa học', '12', 'Hóa vô cơ', 'Khá', 'Kim loại nào có độ âm điện cao nhất?', '["Na","K","Ca","Mg"]'::jsonb, 'K', 'Trong kim loại kiềm, K có độ âm điện thấp nhất (âm điện cao nhất).', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Ngữ văn', '12', 'Văn học', 'Khá', 'Tác phẩm "Truyện Kiều" của Nguyễn Du thuộc thể loại gì?', '["Truyện thơ Nôm","Truyện ngắn","Tiểu thuyết","Kịch thơ"]'::jsonb, 'Truyện thơ Nôm', '"Truyện Kiều" là truyện thơ Nôm, gồm 3254 câu thơ lục bát.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Ngữ văn', '12', 'Văn học', 'Nâng cao', 'Nhân vật chính trong "Chí Phèo" của Nam Cao là ai?', '["Chí Phèo","Thị Nở","Lão Hạc","Với Lão"]'::jsonb, 'Chí Phèo', 'Chí Phèo là nhân vật chính, biểu tượng cho số phận con người bị tha hóa.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Tiếng Anh', '12', 'Ngữ pháp', 'Cơ bản', 'Choose the correct form: She _____ to school every day.', '["go","goes","going","gone"]'::jsonb, 'goes', 'Với chủ ngữ ngôi thứ ba số ít, động từ thêm -s: go -> goes.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Tiếng Anh', '12', 'Từ vựng', 'Khá', 'Từ nào sau đây có nghĩa là "khuyến khích"?', '["encourage","discourage","prevent","forbid"]'::jsonb, 'encourage', 'Encourage = khuyến khích, trái nghĩa với discourage = ngăn cản.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Toán', '11', 'Hình học', 'Cơ bản', 'Trong mặt phẳng tọa độ, phương trình đường thẳng qua 2 điểm (1,2) và (3,4) là?', '["y = x + 1","y = x","y = 2x - 1","y = x + 2"]'::jsonb, 'y = x + 1', 'Hệ số góc m = (4-2)/(3-1) = 1, phương trình y - 2 = 1(x - 1) => y = x + 1.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Vật lý', '11', 'Cơ học', 'Khá', 'Một vật rơi tự do từ độ cao 20m. Vận tốc khi chạm đất là bao nhiêu? (g = 10m/s²)', '["10 m/s","14 m/s","20 m/s","40 m/s"]'::jsonb, '20 m/s', 'v = √(2gh) = √(2*10*20) = √400 = 20 m/s.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Hóa học', '11', 'Hóa vô cơ', 'Cơ bản', 'Chất nào sau đây là bazơ?', '["HCl","NaOH","CO2","H2SO4"]'::jsonb, 'NaOH', 'NaOH là bazơ, HCl và H2SO4 là axit, CO2 là khí.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Ngữ văn', '11', 'Ngữ pháp', 'Cơ bản', 'Từ loại của từ "chạy" trong câu "Cậu bé chạy nhanh" là gì?', '["Danh từ","Động từ","Tính từ","Phó từ"]'::jsonb, 'Động từ', '"Chạy" là động từ chỉ hành động.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Tiếng Anh', '11', 'Ngữ pháp', 'Khá', 'Complete the sentence: If I _____ rich, I would travel around the world.', '["am","were","was","be"]'::jsonb, 'were', 'Câu điều kiện loại 2: If + S + were/V-ed, S + would + V.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Toán', '10', 'Đại số', 'Cơ bản', 'Giải phương trình: 2x + 3 = 7', '["x = 1","x = 2","x = 3","x = 4"]'::jsonb, 'x = 2', '2x + 3 = 7 => 2x = 4 => x = 2.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Vật lý', '10', 'Cơ học', 'Cơ bản', 'Đơn vị của lực trong hệ SI là?', '["N","J","W","Pa"]'::jsonb, 'N', 'N (Newton) là đơn vị của lực.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Hóa học', '10', 'Cơ bản', 'Cơ bản', 'Nguyên tử gồm những hạt nào?', '["Electron và proton","Neutron và proton","Electron, proton, neutron","Chỉ electron"]'::jsonb, 'Electron, proton, neutron', 'Nguyên tử gồm 3 hạt cơ bản: electron, proton, neutron.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Ngữ văn', '10', 'Ngữ pháp', 'Cơ bản', 'Từ loại của từ "đỏ" trong câu "Hoa đỏ" là gì?', '["Danh từ","Động từ","Tính từ","Đại từ"]'::jsonb, 'Tính từ', '"Đỏ" là tính từ chỉ màu sắc.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Tiếng Anh', '10', 'Từ vựng', 'Cơ bản', 'What is the meaning of "happy"?', '["Buồn","Vui vẻ","Giận dữ","Mệt mỏi"]'::jsonb, 'Vui vẻ', 'Happy = vui vẻ, hạnh phúc.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Sinh học', '10', 'Di truyền', 'Cơ bản', 'Gen là đơn vị di truyền cơ bản nằm trên nhiễm sắc thể. Ai là người phát hiện ra gen?', '["Charles Darwin","Gregor Mendel","Watson và Crick","Louis Pasteur"]'::jsonb, 'Gregor Mendel', 'Gregor Mendel là cha đẻ của di truyền học hiện đại với các thí nghiệm về đậu Hà Lan.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Sinh học', '10', 'Di truyền', 'Khá', 'Ở người, nhóm máu được di truyền theo quy luật nào?', '["Di truyền liên kết giới tính","Di truyền theo quy luật Mendel","Di truyền đa gen","Di truyền theo quy luật di truyền tế bào"]'::jsonb, 'Di truyền đa gen', 'Nhóm máu ABO được kiểm soát bởi nhiều gen và có kiểu di truyền phức tạp.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Sinh học', '11', 'Sinh thái học', 'Cơ bản', 'Hệ sinh thái là tập hợp các thành phần nào?', '["Chỉ sinh vật","Chỉ môi trường vật lý","Sinh vật và môi trường sống","Chỉ các loài thực vật"]'::jsonb, 'Sinh vật và môi trường sống', 'Hệ sinh thái bao gồm quần xã sinh vật và môi trường vật lý, hóa học nơi chúng sống.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Sinh học', '11', 'Sinh thái học', 'Khá', 'Chuỗi thức ăn là gì?', '["Thứ tự các loài ăn nhau","Danh sách các loài trong hệ sinh thái","Quá trình quang hợp","Vòng tuần hoàn nitơ"]'::jsonb, 'Thứ tự các loài ăn nhau', 'Chuỗi thức ăn thể hiện mối quan hệ dinh dưỡng giữa các loài trong hệ sinh thái.', 'Quiz Dataset');
insert into quiz_questions (subject, grade, topic, difficulty, question, options, answer, explanation, author) values ('Sinh học', '12', 'Công nghệ sinh học', 'Nâng cao', 'Công nghệ gen là gì?', '["Nuôi cấy mô","Sử dụng enzyme hạn chế để cắt DNA","Công nghệ sản xuất vaccine","Công nghệ nhân giống vô tính"]'::jsonb, 'Sử dụng enzyme hạn chế để cắt DNA', 'Công nghệ gen sử dụng enzyme hạn chế để cắt, ghép và nhân bản DNA.', 'Quiz Dataset');
